#include<bits/stdc++.h>
using namespace std;
int n,m;
vector<pair<int,int>> mp[10010];
vector<int> ans;
void dfs(int x)
{
    for(auto& i:mp[x])
    {
        int v=i.first,val=i.second;
        if(val)
        {
            i.second=0;
            dfs(v);
        }
    }
    ans.push_back(x);
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(make_pair(v,1));
        mp[v].push_back(make_pair(u,1));
    }
    dfs(1);
    reverse(ans.begin(),ans.end());
    for(int i:ans)
    {
        printf("%d\n",i);
    }
    return 0;
}
